import { useState } from "react";
import { X, CheckCircle2, MessageCircle, AlertCircle } from "lucide-react";
import Image from "next/image";

interface Props {
    isOpen: boolean;
    onClose: () => void;
    productName: string;
    packLabel: string;
    packPrice: number;
    packBottles: number;
    whatsappKeyword: string;
    productImage?: string;
}

export default function CheckoutModal({
    isOpen,
    onClose,
    productName,
    packLabel,
    packPrice,
    packBottles,
    whatsappKeyword,
    productImage,
}: Props) {
    const [formData, setFormData] = useState({
        name: "",
        phone: "",
        address: "",
        deliveryDate: "",
        paymentOption: "Transfer",
    });
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState("");

    if (!isOpen) return null;

    const getWhatsAppMessage = () => {
        return `Hello Dr., I want to place an order!

*Product:* ${productName}
*Pack:* ${packLabel} (${packBottles} bottle${packBottles > 1 ? "s" : ""})
*Price:* ₦${packPrice.toLocaleString()}

*My Details:*
*Name:* ${formData.name}
*Phone:* ${formData.phone}
*Address:* ${formData.address}
*Delivery Date:* ${formData.deliveryDate}
*Method:* ${formData.paymentOption}

Please confirm my order.`;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        setError("");

        try {
            // 1. Send data to the admin dashboard via API
            const res = await fetch("/api/orders", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    customer: formData.name,
                    phone: formData.phone,
                    product: `${productName} - ${packLabel}`,
                    amount: packPrice,
                    address: formData.address,
                    delivery_date: formData.deliveryDate,
                    payment_option: formData.paymentOption,
                    status: "pending",
                }),
            });

            if (!res.ok) {
                throw new Error("Failed to process order.");
            }

            // 2. Open WhatsApp with pre-filled details
            const encodedMessage = encodeURIComponent(getWhatsAppMessage());
            const whatsappUrl = `https://api.whatsapp.com/send?phone=2349061505041&text=${encodedMessage}`;

            // Navigate to WhatsApp
            window.open(whatsappUrl, "_blank");

            // Close modal
            onClose();

        } catch (err) {
            console.error(err);
            setError("An error occurred while processing your order. Please try again.");
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
            <div
                className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden relative flex flex-col max-h-[90vh]"
                onClick={(e) => e.stopPropagation()}
            >
                {/* Header */}
                <div className="bg-gradient-to-r from-primary to-primary-dark p-6 text-white shrink-0">
                    <button
                        onClick={onClose}
                        className="absolute top-4 right-4 text-white/80 hover:text-white bg-black/10 hover:bg-black/20 rounded-full p-1 transition-colors"
                    >
                        <X size={20} />
                    </button>
                    <h2 className="text-xl font-bold mb-1">Complete Your Order</h2>
                    <p className="text-primary-100 text-sm">Fill in your details for fast delivery.</p>
                </div>

                {/* Order Summary */}
                <div className="bg-slate-50 dark:bg-slate-800/50 p-4 border-b border-gray-100 dark:border-white/5 shrink-0 flex items-center gap-4">
                    {productImage && (
                        <div className="w-16 h-16 relative bg-white dark:bg-slate-800 rounded-xl border border-gray-200 dark:border-white/10 p-1 flex-shrink-0">
                            <Image src={productImage} alt={productName} fill className="object-contain" />
                        </div>
                    )}
                    <div>
                        <p className="font-bold text-dark dark:text-white text-sm">{productName}</p>
                        <p className="text-xs text-slate-500 mb-1">{packLabel} ({packBottles} bottles)</p>
                        <p className="font-bold text-primary text-lg">₦{packPrice.toLocaleString()}</p>
                    </div>
                </div>

                {/* Form Body - Scrollable */}
                <div className="p-6 overflow-y-auto">
                    {error && (
                        <div className="mb-4 p-3 bg-red-50 text-red-600 border border-red-200 rounded-xl text-sm flex items-start gap-2">
                            <AlertCircle size={16} className="mt-0.5 shrink-0" />
                            <p>{error}</p>
                        </div>
                    )}

                    <form id="checkout-form" onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Full Name</label>
                            <input
                                type="text"
                                required
                                className="w-full px-4 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-primary/50 focus:border-primary outline-none transition-all dark:text-white"
                                placeholder="e.g. Chukwuemeka Okoye"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Phone Number (WhatsApp preferred)</label>
                            <input
                                type="tel"
                                required
                                className="w-full px-4 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-primary/50 focus:border-primary outline-none transition-all dark:text-white"
                                placeholder="e.g. 08012345678"
                                value={formData.phone}
                                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Full Delivery Address</label>
                            <textarea
                                required
                                rows={2}
                                className="w-full px-4 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-primary/50 focus:border-primary outline-none transition-all dark:text-white resize-none"
                                placeholder="Include House Number, Street, and State"
                                value={formData.address}
                                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                            ></textarea>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Delivery Date</label>
                                <input
                                    type="date"
                                    required
                                    min={new Date().toISOString().split('T')[0]} // Cannot select past dates
                                    className="w-full px-4 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-primary/50 focus:border-primary outline-none transition-all dark:text-white"
                                    value={formData.deliveryDate}
                                    onChange={(e) => setFormData({ ...formData, deliveryDate: e.target.value })}
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Payment Method</label>
                                <select
                                    className="w-full px-4 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-primary/50 focus:border-primary outline-none transition-all dark:text-white"
                                    value={formData.paymentOption}
                                    onChange={(e) => setFormData({ ...formData, paymentOption: e.target.value })}
                                >
                                    <option value="Transfer">Bank Transfer on Delivery</option>
                                    <option value="Cash">Cash on Delivery</option>
                                </select>
                            </div>
                        </div>
                    </form>
                </div>

                {/* Footer */}
                <div className="p-6 border-t border-gray-100 dark:border-white/5 bg-slate-50 dark:bg-slate-800/50 shrink-0">
                    <div className="flex items-center gap-2 text-xs text-amber-700 dark:text-amber-400 bg-amber-50 dark:bg-amber-500/10 p-3 rounded-lg border border-amber-200/50 dark:border-amber-500/20 mb-4">
                        <CheckCircle2 size={16} className="shrink-0" />
                        <p>You will pay <strong>₦{packPrice.toLocaleString()}</strong> exactly when the product is delivered to you.</p>
                    </div>
                    <button
                        type="submit"
                        form="checkout-form"
                        disabled={isSubmitting}
                        className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-primary to-primary-dark hover:from-primary-dark hover:to-primary-700 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg shadow-primary/20 hover:-translate-y-0.5 disabled:opacity-70 disabled:hover:translate-y-0"
                    >
                        {isSubmitting ? (
                            <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                        ) : (
                            <>
                                <MessageCircle size={20} />
                                Send Order via WhatsApp
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

import { Check, MessageCircle, Star } from "lucide-react";
import { PricingPack, getWhatsAppLink } from "@/lib/products";

interface Props {
  pack: PricingPack;
  productName: string;
  whatsappKeyword: string;
  onOrder: () => void;
}

export default function PricingCard({ pack, productName, whatsappKeyword, onOrder }: Props) {
  const savings = pack.originalPrice - pack.salePrice;
  const savingsPct = Math.round((savings / pack.originalPrice) * 100);

  return (
    <div
      className={`relative flex flex-col h-full rounded-3xl overflow-hidden transition-all duration-500 hover:-translate-y-1 ${pack.recommended
        ? "bg-gradient-to-b from-white to-primary-50 dark:from-slate-800 dark:to-slate-900 ring-2 ring-primary shadow-2xl shadow-primary/15"
        : "bg-white dark:bg-slate-800/40 border border-gray-200/80 dark:border-white/5 shadow-md hover:shadow-xl"
        }`}
    >
      {pack.recommended && (
        <div className="bg-gradient-to-r from-primary to-primary-dark text-white text-xs font-bold px-3 py-2 text-center uppercase tracking-wider flex items-center justify-center gap-1.5">
          <Star className="w-3.5 h-3.5 fill-current" /> Most Popular
        </div>
      )}

      <div className="p-5 flex-1 flex flex-col">
        {/* Pack Name */}
        <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider text-center mb-2">
          {pack.label}
        </p>

        {/* Price */}
        <div className="text-center mb-3">
          <div className="flex items-baseline justify-center gap-1">
            <span className="text-3xl font-extrabold text-dark dark:text-white">₦{pack.salePrice.toLocaleString()}</span>
          </div>
          <div className="flex items-center justify-center gap-2 mt-1">
            <span className="text-sm text-slate-400 dark:text-slate-500 line-through">₦{pack.originalPrice.toLocaleString()}</span>
            <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-500/10 px-2 py-0.5 rounded-full">
              -{savingsPct}%
            </span>
          </div>
        </div>

        {/* Bottles */}
        <div className="flex items-center justify-center gap-2 mb-4">
          <span className="w-7 h-7 bg-gradient-to-br from-primary/10 to-primary/20 dark:from-primary/20 dark:to-primary/30 rounded-full flex items-center justify-center text-primary dark:text-primary-light font-bold text-xs">
            {pack.bottles}
          </span>
          <span className="text-xs text-slate-600 dark:text-slate-400 font-medium">
            {pack.bottles} {pack.bottles === 1 ? "bottle" : "bottles"}
          </span>
        </div>

        {/* Description */}
        <p className="text-xs text-slate-500 dark:text-slate-400 text-center mb-5 leading-relaxed">
          {pack.description}
        </p>

        {pack.includedProducts && pack.includedProducts.length > 0 && (
          <div className="mb-5 bg-slate-50 dark:bg-slate-900/50 rounded-xl p-3 border border-slate-100 dark:border-slate-800">
            <p className="text-xs font-semibold text-slate-600 dark:text-slate-300 mb-2">Included Products:</p>
            <ul className="space-y-1.5">
              {pack.includedProducts.map((prod, idx) => (
                <li key={idx} className="text-xs text-slate-500 dark:text-slate-400 flex items-start gap-2">
                  <span className="text-primary/70 mt-0.5">•</span>
                  <span>{prod}</span>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Order Button */}
        <button
          onClick={onOrder}
          className={`mt-auto flex items-center justify-center gap-2 w-full py-3 rounded-xl font-bold text-sm transition-all duration-300 hover:-translate-y-0.5 ${pack.recommended
            ? "bg-gradient-to-r from-primary to-primary-dark hover:from-primary-dark hover:to-primary-700 text-white shadow-lg shadow-primary/20"
            : "bg-primary hover:bg-primary-dark text-white shadow-md"
            }`}
        >
          <MessageCircle size={15} />
          Order Now
        </button>
      </div>
    </div>
  );
}

import Image from "next/image";
import { LucideIcon, Shield, Truck, CreditCard, Clock } from "lucide-react";

interface Badge {
  title: string;
  desc: string;
  gradient: string;
  icon?: LucideIcon;
  image?: string;
}

const badges: Badge[] = [
  {
    title: "NAFDAC Approved",
    desc: "All products certified & approved",
    gradient: "from-emerald-500 to-green-600",
    image: "/images/nafdac-logo.svg"
  },
  { icon: Truck, title: "Free Delivery", desc: "Delivered to your doorstep", gradient: "from-blue-500 to-cyan-600" },
  { icon: CreditCard, title: "Pay on Delivery", desc: "Pay when you receive your order", gradient: "from-amber-500 to-orange-600" },
  { icon: Clock, title: "24/7 Support", desc: "WhatsApp anytime", gradient: "from-purple-500 to-violet-600" },
];

export default function TrustBadges() {
  return (
    <section className="bg-gradient-to-r from-primary-50/50 via-white to-primary-50/50 dark:from-slate-900 dark:via-slate-800/50 dark:to-slate-900 border-y border-primary/5 dark:border-white/5 py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
          {badges.map((badge) => {
            const Icon = badge.icon;
            return (
              <div key={badge.title} className="flex flex-col items-center text-center gap-3 group">
                <div className={`w-14 h-14 bg-gradient-to-br ${badge.gradient} rounded-2xl flex items-center justify-center shadow-lg group-hover:shadow-xl transition-all duration-300 group-hover:-translate-y-1 p-2`}>
                  {badge.image ? (
                    <div className="relative w-full h-full">
                      <Image
                        src={badge.image}
                        alt={badge.title}
                        fill
                        className="object-contain"
                      />
                    </div>
                  ) : Icon ? (
                    <Icon className="text-white" size={24} />
                  ) : null}
                </div>
                <div>
                  <p className="font-bold text-dark dark:text-white text-sm">{badge.title}</p>
                  <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">{badge.desc}</p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
